impl Widget {
    pub fn make() -> Widget { Widget { id: 0 } }
    pub fn get_id(&self) -> u32 { self.id }
}

impl Handle {
    pub fn null() -> Handle { Handle { raw: std::ptr::null_mut() } }
}

impl Probe {
    pub fn read(&self) -> u32 { self.value }
    pub fn rust_only(&self) -> u32 { self.value + 1 }
    pub fn rust_block_method(&self) -> u32 { self.value + 100 }
}

inline ::std::uint32_t Probe::read() const { return value; }
inline ::std::uint32_t Probe::cpp_only() const { return value + 2; }
inline ::std::uint32_t Probe::cpp_or_json() const { return value + 3; }
inline ::std::uint32_t Probe::not_rust() const { return value + 4; }

impl Logger {
    pub fn make() -> Logger { Logger { seen: 0 } }
    pub fn record(&mut self) -> u32 { self.seen += 1; self.seen }
}

Logger Logger::make() { return Logger{0}; }

::std::uint32_t Logger::record() {
    seen += 1;
    std::printf("Logger seen=%u\n", seen);
    return seen;
}

impl Counter {
    pub fn make() -> Counter { Counter { value: 0 } }
    pub fn bump(&mut self) -> u32 { self.value += 1; self.value }
    pub fn read(&self) -> u32 { self.value }
}

inline Counter Counter::make() { return Counter{0}; }
inline ::std::uint32_t Counter::bump() { value += 1; return value; }
inline ::std::uint32_t Counter::read() const { return value; }

impl<T> Pair<T> {
    pub fn first_ptr(&self) -> *mut T { self.first }
    // In Rust, method-level type parameters live on the function, not
    // the impl. Pyxis's `impl<T, Y> Pair<T> { fn cast_first ... }` form
    // maps to this Rust shape.
    pub fn cast_first<Y>(&self) -> *mut Y { self.first as *mut Y }
}

template <class T>
inline T* Pair<T>::first_ptr() const { return first; }

template <class T> template <class Y>
inline Y* Pair<T>::cast_first() const { return reinterpret_cast<Y*>(first); }

impl World {
    pub fn from_id(id: u64) -> World { World { id } }
}
